import { NextResponse } from "next/server";
import path from "path";
import fs from "fs-extra";
import poppler from "pdf-poppler";

export async function POST(req: Request) {
  try {
    // Parse form data
    const formData = await req.formData();
    const file = formData.get("file") as File;

    if (!file) {
      return NextResponse.json({ error: "No file uploaded" }, { status: 400 });
    }

    // Define paths
    const uploadDir = path.join(process.cwd(), "public/uploads");
    await fs.ensureDir(uploadDir);

    const filePath = path.join(uploadDir, file.name);
    const fileBuffer = Buffer.from(await file.arrayBuffer());

    // Save file to public/uploads
    await fs.writeFile(filePath, fileBuffer);

    // Convert PDF to images
    const images = await convertPDFToImages(filePath);

    return NextResponse.json({ message: "Upload successful", images });
  } catch (error) {
    console.error("Error:", error);
    return NextResponse.json({ error: "Upload failed" }, { status: 500 });
  }
}

// Function to convert PDF to images
async function convertPDFToImages(pdfPath: string) {
  const outputDir = path.dirname(pdfPath);
  const outputPrefix = path.basename(pdfPath, ".pdf");

  const options = {
    format: "png",
    out_dir: outputDir,
    out_prefix: outputPrefix,
    scale: 1024,
  };

  try {
    await poppler.convert(pdfPath, options);
    const imageFiles = await fs.readdir(outputDir);
    return imageFiles.filter((file) => file.startsWith(outputPrefix));
  } catch (error) {
    console.error("Poppler error:", error);
    return [];
  }
}
